INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Perplexity and burstiness scoring$q$, $q$Analyzes word predictability and sentence-length variation to estimate the likelihood text was AI-generated.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Sentence-level highlighting$q$, $q$Flags the specific sentences or passages most likely to have been written by AI.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Source/model detection$q$, $q$Attempts to identify which underlying AI model may have generated a given passage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Batch scanning for classrooms$q$, $q$Lets educators scan large volumes of student submissions at once.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Plagiarism and writing report$q$, $q$Combines AI-detection scoring with a broader originality and writing report.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Browser extension$q$, $q$Scans text directly within the browser without needing to copy content into the web app.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$API access$q$, $q$Lets developers and platforms integrate GPTZero's detection directly into their own products.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$LMS integrations$q$, $q$Connects with learning management systems for classroom-scale deployment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Early mainstream brand recognition and trust in education settings$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Generous free tier for casual, low-volume use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Batch scanning built specifically for classroom-scale grading$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Developer API available for platform integration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Detection models are continuously updated$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Like all AI detectors, false positives and negatives are possible and accuracy is debated$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Per-word pricing can become expensive for heavy users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Advanced features such as unlimited batch scanning and API access are gated behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Non-native English writing can be flagged at higher rates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Future product direction is uncertain following the 2026 Superhuman acquisition$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$What is GPTZero?$q$, $q$GPTZero is an AI-generated text detection tool that analyzes writing to estimate the likelihood it was produced by an AI model such as ChatGPT.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Who founded GPTZero?$q$, $q$GPTZero was founded by Edward Tian, a Princeton University undergraduate, who launched it in January 2023.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Is GPTZero free to use?$q$, $q$GPTZero offers a free plan with 10,000 words per month; paid plans start at roughly $14.99 per month for higher word limits and additional features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$How accurate is GPTZero?$q$, $q$GPTZero uses perplexity and burstiness analysis to estimate AI authorship, but like all AI detectors it is probabilistic and can produce false positives or negatives, so results should not be treated as absolute proof.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Does GPTZero offer an API?$q$, $q$Yes, API access is available on the Professional plan for developers who want to integrate detection directly into their own products.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$What happened with the Superhuman acquisition?$q$, $q$In June 2026, workplace productivity company Superhuman announced it was acquiring GPTZero, integrating its AI-detection technology into Superhuman's broader product line.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Classroom AI-writing screening$q$, $q$Teachers use batch scanning to check student essays for signs of AI-generated content.$q$, $q$K-12 and higher-education instructors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Editorial originality verification$q$, $q$Publishers and content platforms verify that submitted articles were written by humans before publishing.$q$, $q$Publishers and content platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Enterprise authenticity checks$q$, $q$HR and compliance teams verify the authenticity of submitted written work such as applications or reports.$q$, $q$Enterprise HR and compliance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["10,000 words per month","3 Advanced Scans","Basic AI detection scoring"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Essential$q$, $q$$14.99/month billed monthly; ~$8.33/month billed annually$q$, $q$Monthly or Annual$q$, NULL, $q$["150,000 words per month","Sentence-level highlighting","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Premium$q$, $q$$23.99/month billed monthly; ~$12.99/month billed annually$q$, $q$Monthly or Annual$q$, NULL, $q$["300,000 words per month","Unlimited batch scanning","Source/model detection"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Professional$q$, $q$$45.99/month billed monthly; ~$24.99/month billed annually$q$, $q$Monthly or Annual$q$, NULL, $q$["500,000 words per month","API access","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Classroom / Enterprise$q$, $q$Custom quote$q$, $q$Annual (quoted)$q$, NULL, $q$["Per-seat pricing for schools and organizations","LMS integrations","Dedicated account support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GPTZero is an AI-generated text detection platform founded by Princeton student Edward Tian in January 2023, built to help educators and organizations identify writing likely produced by tools like ChatGPT.$q$, $q$The company scaled rapidly, raising a $3.5 million seed round and later a $10 million Series A, growing to over 19 million registered users and about $30 million in ARR before being acquired by Superhuman in June 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GPTZero scores text using perplexity and burstiness analysis, highlights likely AI-written sentences, attempts to identify the source model, and supports batch scanning for grading large volumes of submissions at once.$q$, $q$The platform also offers a browser extension, LMS and classroom integrations, a plagiarism and writing report, and a developer API for embedding detection into other products.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GPTZero uses a freemium model: a Free plan offers 10,000 words per month, while paid Essential, Premium, and Professional plans scale up in word limits and features, from about $14.99 to $45.99 per month billed monthly.$q$, $q$Annual billing saves roughly 45% versus monthly pricing, and dedicated Classroom and Enterprise plans use custom, per-seat pricing for schools and larger organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Zero-codegen type inference$q$, $q$Infers GraphQL query and variable types live inside the TypeScript type system, with no separate build step to generate files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Schema-aware autocomplete via GraphQLSP$q$, $q$A companion language server plugin provides in-editor autocompletion and diagnostics for GraphQL documents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Fragment masking$q$, $q$Enforces that consumers explicitly unwrap fragment data, encouraging cleaner, component-scoped data-fetching patterns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$TSDoc self-documentation$q$, $q$All APIs are documented with TSDocs, surfacing inline documentation on hover in supporting editors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$urql interoperability$q$, $q$Built to work closely with the urql GraphQL client, with adaptability to other GraphQL clients.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Live editor diagnostics$q$, $q$Flags invalid queries and type mismatches directly in the editor as you write GraphQL documents.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Tagged template literal syntax$q$, $q$GraphQL documents are authored as plain TypeScript tagged template strings, requiring no new file format.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$npm-distributed open source package$q$, $q$Installed as a standard npm dependency with no proprietary tooling or account required.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$No build or codegen step to maintain or forget to re-run$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Types are always accurate and immediately in sync with source changes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Tight editor integration via the GraphQLSP language server plugin$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Completely free and open source$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Encourages cleaner fragment-based data-fetching patterns$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Smaller, newer ecosystem than the long-established GraphQL Code Generator$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Best editor experience currently depends on TypeScript-aware language server support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Tightest first-class integration is with urql rather than every GraphQL client$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Debugging type inference issues requires understanding TypeScript's type system internals$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Less community documentation and tutorial content than more mature codegen tooling$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$What is gql.tada?$q$, $q$gql.tada is a free, open-source TypeScript library that infers fully-typed GraphQL query and variable types directly from your schema, without requiring a separate code-generation step.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Is gql.tada free?$q$, $q$Yes, gql.tada is completely free and open source, distributed via npm with no paid tier or commercial license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Do I still need a build step to use gql.tada?$q$, $q$No separate code-generation build step is required; type inference happens live inside the TypeScript compiler as you write GraphQL documents.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Does gql.tada work with Apollo Client?$q$, $q$gql.tada's core type-inference engine is client-agnostic, though it is most tightly built and documented for use with the urql GraphQL client.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$What is GraphQLSP?$q$, $q$GraphQLSP is a companion TypeScript language server plugin, also maintained by 0no.co, that provides schema-aware autocompletion and diagnostics for GraphQL documents inside supporting editors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$What is fragment masking in gql.tada?$q$, $q$Fragment masking is a pattern that requires consumers of a GraphQL fragment to explicitly unwrap its data rather than accessing fields directly, encouraging cleaner component-level data boundaries.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Type-safe GraphQL queries with urql$q$, $q$TypeScript frontend applications using the urql client adopt gql.tada for live, accurate query typing.$q$, $q$Frontend developers using urql$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Removing a GraphQL codegen build step$q$, $q$Teams replace a traditional GraphQL Code Generator pipeline with gql.tada's live type inference to simplify their build process.$q$, $q$Full-stack TypeScript teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Fragment-based component data requirements$q$, $q$Library and component authors use fragment masking to define clean, type-safe data dependencies for reusable components.$q$, $q$Component library authors and design system teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT-style open-source npm package","Unlimited use in any project","GraphQLSP editor integration","Fragment masking support","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$gql.tada is a free, open-source TypeScript library that infers fully accurate result and variable types for GraphQL queries and fragments directly within the TypeScript type system, eliminating the need for a separate code-generation build step.$q$, $q$Maintained by 0no.co and paired with the companion GraphQLSP language server plugin, gql.tada gives developers live, schema-aware autocompletion and type checking for GraphQL documents written as tagged template strings, right inside their editor.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Because gql.tada performs type inference live inside the TypeScript compiler rather than through a generated-file pipeline, query and variable types are always in sync with the current schema and query text, with nothing to regenerate or go stale.$q$, $q$Features include schema-aware autocompletion via GraphQLSP, 'fragment masking' to enforce clean component-level data boundaries, full TSDoc self-documentation surfaced on hover, and tight interoperability with the urql GraphQL client.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$gql.tada is completely free and open source, distributed via npm with no paid tier, subscription, or commercial license.$q$, $q$There is no hosted service or enterprise edition; it is purely a development-time library that plugs into a project's existing TypeScript toolchain at no cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b8b8b291-3cad-4420-bac2-bf022c3e06c2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
