INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Automated email and SMS review requests$q$, $q$Sends review request campaigns to customers via email and text message to funnel them toward leaving public reviews.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Negative review recovery funnel$q$, $q$Routes dissatisfied customers into a private feedback flow instead of a public review page, protecting online reputation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Multi-site review monitoring dashboard$q$, $q$Tracks and centralizes new reviews from dozens of third-party review sites in one place.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$White-label branding and custom domain$q$, $q$Lets agencies rebrand the entire platform with their own logo and domain for client-facing use.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Review widget and carousel$q$, $q$Embeddable widgets display collected reviews on a client's website for SEO and social proof.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Client reporting and analytics$q$, $q$Provides reporting tools agencies can use to demonstrate review-management ROI to their clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Agency reseller model$q$, $q$Structured for agencies to resell review management as a billable service line under their own brand.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Major review site integrations$q$, $q$Connects with review platforms including Google and Facebook alongside industry-specific directories.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Purpose-built white-label model lets agencies resell as their own product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Negative-review recovery funnel helps protect public reputation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Centralized multi-client dashboard saves agencies time managing many accounts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$14-day free trial with no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$No long-term contracts, with cancellation available at any time$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Per-seat pricing can add up for agencies managing many clients$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$SMS review request campaigns cost extra on top of the base plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Pricing sits higher than some single-location review tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Primarily agency-oriented, making it less ideal for a single independent business$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Some users report price increases and a preference for annual billing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$What is Grade.us?$q$, $q$Grade.us is a white-label review management and reputation marketing platform built for marketing agencies to generate, monitor, and market reviews on behalf of their clients.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Who is Grade.us designed for?$q$, $q$Grade.us is designed primarily for digital marketing agencies and SEO consultancies managing review programs for multiple small-business clients, rather than for a single business managing its own reviews.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$How much does Grade.us cost?$q$, $q$Grade.us prices per seat per month, starting at roughly $25/seat/month for the Partner plan and scaling up to Agency, Professional, and Solo tiers, with SMS campaigns billed as an add-on.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Can I white-label Grade.us under my own agency brand?$q$, $q$Yes, Grade.us can be fully white-labeled with an agency's own logo, branding, and a custom domain so clients never see the Grade.us name.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Does Grade.us send SMS review requests?$q$, $q$Yes, Grade.us supports SMS text message review request campaigns in addition to email, billed as a separate add-on on top of the base plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Is there a free trial for Grade.us?$q$, $q$Yes, Grade.us offers a 14-day free trial with no credit card required to get started.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Agency review management reselling$q$, $q$Marketing agencies resell review management as a white-labeled, billable service to their local-business clients.$q$, $q$Digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Local SEO review building$q$, $q$SEO consultants use review generation and widgets to strengthen a client's local search visibility.$q$, $q$SEO consultants and local-marketing specialists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Multi-location reputation monitoring$q$, $q$Businesses with multiple locations centralize review monitoring and response across all sites in one dashboard.$q$, $q$Multi-location businesses and franchise operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Partner$q$, $q$$25/seat/month$q$, $q$Monthly$q$, NULL, $q$["Agency/reseller access","API access","Basic white label","Email review request campaigns"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Agency$q$, $q$$40/seat/month$q$, $q$Monthly$q$, NULL, $q$["Agency/reseller access","API access","Basic white label","Email review request campaigns","Floating review carousel"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Professional$q$, $q$$60/seat/month$q$, $q$Monthly$q$, NULL, $q$["Agency/reseller access","Basic white label","Email review request campaigns","Floating review carousel","Expanded client capacity"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$Solo$q$, $q$$110/seat/month$q$, $q$Monthly$q$, NULL, $q$["Agency/reseller access","Basic white label","Email review request campaigns","Floating review carousel","Highest client capacity tier"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grade.us is a white-label review management and reputation marketing platform built specifically for marketing agencies, consultants, and SEOs to manage review generation, monitoring, and marketing on behalf of their client businesses.$q$, $q$Founded in 2013 and headquartered in Montclair, New Jersey, Grade.us became a subsidiary of Traject in 2020 and continues to operate as an agency-first product distinct from single-brand review tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core workflows include automated email and SMS review request campaigns that route unhappy customers into a private feedback flow, centralized multi-site review monitoring across dozens of third-party review platforms, and embeddable review widgets for client websites.$q$, $q$The platform's defining feature is full white-labeling, including custom branding and a unique domain, letting agencies resell Grade.us under their own brand to their client base.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Grade.us prices per seat per month across four tiers: Partner (~$25), Agency (~$40), Professional (~$60), and Solo (~$110), with SMS review request campaigns billed as a separate add-on.$q$, $q$A 14-day free trial with no credit card required is available, and the company advertises no long-term contracts, allowing cancellation at any time.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1a03e2a-1f45-466c-a273-8c8ac39242e0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
